impl<R: UserSettingsProjectionRepository> UserSettingsEventHandler for UserSettingsProjector<R> {

    async fn on_created(&self, event: UserSettingsCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = UserSettingsProjection::new(
            event.id,
            event.user_id,
            event.theme,
            event.language,
            event.timezone,
            event.notifications_enabled,
            event.email_notifications,
            event.sms_notifications,
            event.mfa_enabled,
            event.custom_settings,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: UserSettingsUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.theme = event.theme;
            projection.language = event.language;
            projection.timezone = event.timezone;
            projection.notifications_enabled = event.notifications_enabled;
            projection.email_notifications = event.email_notifications;
            projection.sms_notifications = event.sms_notifications;
            projection.mfa_enabled = event.mfa_enabled;
            projection.custom_settings = event.custom_settings;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: UserSettingsDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

